module JDBCDataTypeMapping =
  struct
    type nonrec t = (JDBCDataType.t * GlueRecordType.t) list
    let make i = i
    let of_header xs =
      make
        (List.filter_map xs
           ~f:(fun (k, v) ->
                 (Base.String.chop_prefix k ~prefix:"x-amz-meta-") |>
                   (Option.map
                      ~f:(fun chopped ->
                            ((JDBCDataType.of_string chopped),
                              (GlueRecordType.of_string v))))))
    let to_value xs =
      (xs |>
         (List.map
            ~f:(fun (x, y) ->
                  (JDBCDataType.to_value x) |>
                    (fun x ->
                       (GlueRecordType.to_value y) |> (fun y -> (x, y))))))
        |> (fun x -> `Map x)
    let to_query v = to_query to_value v
    let to_header _ =
      failwithf "to_header is not implemented for Map_shape objects" ()
    let of_xml _ =
      failwith "of_xml_converter_of_shape: Map_shape case not implemented"
    let of_json j =
      object_of_json ~key_of_string:JDBCDataType.of_string
        ~of_json:GlueRecordType.of_json j
    let to_json v = composed_to_json to_value v
  end
