      | `OperationTimeoutException e ->
          `Assoc
            [("error", (`String "OperationTimeoutException"));
            ("details", (OperationTimeoutException.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
