module CheckSchemaVersionValidityResponse =
  struct
    type nonrec t =
      {
      valid: IsVersionValid.t option
        [@ocaml.doc
          "Return true, if the schema is valid and false otherwise."];
      error: SchemaValidationError.t option
        [@ocaml.doc "A validation failure error message."]}
    type nonrec error =
      [ `AccessDeniedException of AccessDeniedException.t 
      | `InternalServiceException of InternalServiceException.t 
      | `InvalidInputException of InvalidInputException.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?valid = fun ?error -> fun () -> { valid; error }
    let error_of_json name json =
      match name with
      | "AccessDeniedException" ->
          `AccessDeniedException (AccessDeniedException.of_json json)
      | "InternalServiceException" ->
          `InternalServiceException (InternalServiceException.of_json json)
      | "InvalidInputException" ->
          `InvalidInputException (InvalidInputException.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "AccessDeniedException" ->
          `AccessDeniedException (AccessDeniedException.of_xml xml)
      | "InternalServiceException" ->
          `InternalServiceException (InternalServiceException.of_xml xml)
      | "InvalidInputException" ->
          `InvalidInputException (InvalidInputException.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `AccessDeniedException e ->
          `Assoc
            [("error", (`String "AccessDeniedException"));
            ("details", (AccessDeniedException.to_json e))]
      | `InternalServiceException e ->
          `Assoc
            [("error", (`String "InternalServiceException"));
            ("details", (InternalServiceException.to_json e))]
      | `InvalidInputException e ->
          `Assoc
            [("error", (`String "InvalidInputException"));
            ("details", (InvalidInputException.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("Valid", (Option.map x.valid ~f:IsVersionValid.to_value));
        ("Error", (Option.map x.error ~f:SchemaValidationError.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let error =
        (Option.map ~f:SchemaValidationError.of_xml)
          (Xml.child xml_arg0 "Error") in
      let valid =
        (Option.map ~f:IsVersionValid.of_xml) (Xml.child xml_arg0 "Valid") in
      make ?error ?valid ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let error = field_map json__ "Error" SchemaValidationError.of_json in
      let valid = field_map json__ "Valid" IsVersionValid.of_json in
      make ?error ?valid ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "Validates the supplied schema. This call has no side effects, it simply validates using the supplied schema using DataFormat as the format. Since it does not take a schema set name, no compatibility checks are performed."]
