      numFalsePositives: RecordsCount.t option
        [@ocaml.doc
          "The number of nonmatches in the data that the transform incorrectly classified as a match, in the confusion matrix for your transform."];
      numTrueNegatives: RecordsCount.t option
        [@ocaml.doc
          "The number of nonmatches in the data that the transform correctly rejected, in the confusion matrix for your transform."];
      numFalseNegatives: RecordsCount.t option
        [@ocaml.doc
          "The number of matches in the data that the transform didn't find, in the confusion matrix for your transform."]}
    let make ?numTruePositives =
      fun ?numFalsePositives ->
        fun ?numTrueNegatives ->
          fun ?numFalseNegatives ->
            fun () ->
              {
                numTruePositives;
                numFalsePositives;
                numTrueNegatives;
                numFalseNegatives
              }
    let to_value x =
      structure_to_value
        [("NumTruePositives",
           (Option.map x.numTruePositives ~f:RecordsCount.to_value));
        ("NumFalsePositives",
          (Option.map x.numFalsePositives ~f:RecordsCount.to_value));
        ("NumTrueNegatives",
          (Option.map x.numTrueNegatives ~f:RecordsCount.to_value));
        ("NumFalseNegatives",
          (Option.map x.numFalseNegatives ~f:RecordsCount.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let numFalseNegatives =
        (Option.map ~f:RecordsCount.of_xml)
          (Xml.child xml_arg0 "NumFalseNegatives") in
      let numTrueNegatives =
        (Option.map ~f:RecordsCount.of_xml)
          (Xml.child xml_arg0 "NumTrueNegatives") in
      let numFalsePositives =
        (Option.map ~f:RecordsCount.of_xml)
          (Xml.child xml_arg0 "NumFalsePositives") in
      let numTruePositives =
        (Option.map ~f:RecordsCount.of_xml)
          (Xml.child xml_arg0 "NumTruePositives") in
      make ?numFalseNegatives ?numTrueNegatives ?numFalsePositives
        ?numTruePositives ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let numFalseNegatives =
        field_map json__ "NumFalseNegatives" RecordsCount.of_json in
      let numTrueNegatives =
        field_map json__ "NumTrueNegatives" RecordsCount.of_json in
      let numFalsePositives =
        field_map json__ "NumFalsePositives" RecordsCount.of_json in
      let numTruePositives =
        field_map json__ "NumTruePositives" RecordsCount.of_json in
      make ?numFalseNegatives ?numTrueNegatives ?numFalsePositives
        ?numTruePositives ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "The confusion matrix shows you what your transform is predicting accurately and what types of errors it is making. For more information, see Confusion matrix in Wikipedia."]
