module ConnectionProperties =
  struct
    type nonrec t = (ConnectionPropertyKey.t * ValueString.t) list
    let make i =
      let open Result in
        ok_or_failwith
          ((check_list_max i ~max:100) >>=
             (fun () -> check_list_min i ~min:0));
        i
    let of_header xs =
      make
        (List.filter_map xs
           ~f:(fun (k, v) ->
                 (Base.String.chop_prefix k ~prefix:"x-amz-meta-") |>
                   (Option.map
                      ~f:(fun chopped ->
                            ((ConnectionPropertyKey.of_string chopped),
                              (ValueString.of_string v))))))
    let to_value xs =
      (xs |>
         (List.map
            ~f:(fun (x, y) ->
                  (ConnectionPropertyKey.to_value x) |>
                    (fun x -> (ValueString.to_value y) |> (fun y -> (x, y))))))
        |> (fun x -> `Map x)
    let to_query v = to_query to_value v
    let to_header _ =
      failwithf "to_header is not implemented for Map_shape objects" ()
    let of_xml _ =
      failwith "of_xml_converter_of_shape: Map_shape case not implemented"
    let of_json j =
      object_of_json ~key_of_string:ConnectionPropertyKey.of_string
        ~of_json:ValueString.of_json j
    let to_json v = composed_to_json to_value v
  end
module Connection =
