      authenticationConfiguration: AuthenticationConfiguration.t option
        [@ocaml.doc "The authentication properties of the connection."];
      connectionSchemaVersion: ConnectionSchemaVersion.t option
        [@ocaml.doc
          "The version of the connection schema for this connection. Version 2 supports properties for specific compute environments."];
      compatibleComputeEnvironments: ComputeEnvironmentList.t option
        [@ocaml.doc
